INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Listening', 'How are you feeling?', '기분이 어떠니?', '기분 묻기', 11);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Listening', 'I’m glad to hear that.', '그 말을 들으니 기쁘구나.', '감정의 원인(to부정사)', 11);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Listening', 'I’m feeling happy. Today’s lunch is great.', '기분이 좋아. 오늘 점심이 아주 맛있거든.', '감정 표현', 11);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Listening', 'I’m sorry to hear that. My friend is sick.', '그 소식을 들으니 안타깝구나. 내 친구가 아파서.', '안타까움 표현', 11);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Listening', 'Yes. I finally booked four tickets for the VTS concert!', '응. 드디어 VTS 콘서트 티켓 4장을 예매했어!', '현재완료 시제', 12);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Listening', 'I’m happier than ever.', '어느 때보다 더 기뻐.', '비교급 표현', 12);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Listening', 'I’m nervous. I forgot to bring my math homework.', '긴장돼. 수학 숙제를 가져오는 걸 잊었어.', '감정 표현', 13);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Main', 'Laughter is human. We laugh out loud when we hear a joke.', '웃음은 인간적이다. 우리는 농담을 듣거나 재미있는 것을 볼 때 크게 웃는다.', '시간의 접속사', 14);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Main', '“Ha-ha” is a form of written laughter. Everyone knows what it means.', '“하하”는 서면 웃음의 한 형태이다. 모든 사람이 그것이 무엇을 의미하는지 안다.', '간접의문문', 14);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Main', 'Another form of written laughter is LOL. It stands for “Laughing Out Loud.”', '서면 웃음의 또 다른 형태는 LOL이다. 그것은 “Laughing Out Loud”의 약자이다.', '어구 표현', 15);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Main', 'People also use ROFL quite often, which means “Rolling On the Floor Laughing.”', '사람들은 또한 ROFL도 꽤 자주 사용하는데, 이것은 “바닥을 구르며 웃기”를 의미한다.,G0109', '계속적 용법의 관계대명사', 15);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Main', 'XD is an emoticon which is a group of letters or symbols used to represent a facial expression.', 'XD는 얼굴 표정을 나타내기 위해 사용되는 문자나 기호의 집합인 이모티콘이다.', '주격 관계대명사', 15);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Main', 'Laughing marks can represent our facial expressions and deliver our voice tones.', '웃음 표시들은 우리의 얼굴 표정을 나타내고 목소리 톤을 전달할 수 있다.', '어휘(동사)', 17);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Focus In', 'I’m going to show you this photo which my friend Amy sent to me.', '내 친구 Amy가 나에게 보낸 이 사진을 너에게 보여줄게.', '계속적 용법의 관계대명사', 18);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Focus In', 'Please tell me what time it is.', '몇 시인지 알려줘.', '간접의문문', 19);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Grammar', 'Can you guess what the emoji means?', '그 이모지가 무엇을 의미하는지 추측할 수 있니?', '간접의문문', 22);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Reading', 'Red on a traffic light means “Stop”.', '신호등의 빨간색은 “정지”를 의미한다.', '어휘(동사)', 23);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Reading', 'Do you know what the color red means?', '빨간색이 무엇을 의미하는지 아니?', '간접의문문', 23);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Reading', 'I use emojis when I express my feelings in written messages.', '나는 서면 메시지로 내 감정을 표현할 때 이모지를 사용한다.', '시간의 접속사', 24);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (21, 'Reading', 'I’m glad to get a message from my grandma.', '할머니로부터 메시지를 받아서 기뻐.', '감정의 원인(to부정사)', 12);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Listening', 'Let’s talk about the class party.', '우리 학급 파티에 대해 이야기해 보자.', '대화 시작하기', 28);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Listening', 'Who will make sandwiches? I will. I can do it well.', '누가 샌드위치를 만들 거니? 제가 할게요. 제가 잘할 수 있어요.', '지원하기', 28);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Listening', 'Thank you for volunteering.', '자원해 줘서 고마워.', '감사 표현', 28);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Listening', 'Why don’t we clean the place together?', '그곳을 함께 청소하는 게 어떠니?', '제안하기', 30);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Listening', 'How about putting some flower pots around the bench?', '벤치 주변에 화분 몇 개를 놓는 건 어때?', '제안하기', 30);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Listening', 'Thank you for suggesting great ideas', ' everyone.,모두 좋은 아이디어를 제안해 줘서 고마워요.,G0203', '감사 표현', 30);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Main', 'My parents were making me work on the neighborhood project.', '부모님은 내가 동네 프로젝트에서 일하게 하셨다.', '사역동사', 32);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Main', 'It was full of dirty trash you can imagine.', '그곳은 여러분이 상상할 수 있는 온갖 더러운 쓰레기들로 가득했다.', '어구 표현', 32);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Main', 'I didn’t think that we could clean up this awful mess.', '나는 우리가 이 지독한 엉망진창을 청소할 수 있을 것이라 생각지 않았다.', '과거의 추측/생각', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Main', 'By lunchtime', ' I was hot, sweaty, and glad my dad had made me wear gloves.,점심때쯤 나는 덥고 땀이 났지만 아버지가 나에게 장갑을 끼게 하셨던 것이 다행이었다.,G0208', '과거완료 / 사역동사', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Main', 'At the end of the day', ' I had to admit the lot looked much better.,하루가 끝날 때, 나는 그 부지가 훨씬 좋아 보인다는 것을 인정해야 했다.,G0209', '비교급 강조', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Main', 'I stopped complaining when I found the plants had started popping up!', '식물들이 싹을 틔우기 시작한 것을 발견했을 때 나는 불평을 그만두었다!', '과거완료 시제', 34);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Main', 'The bean plants grew an inch', ' and the tomatoes doubled in size in just a few days.,콩 식물들은 1인치 자랐고, 토마토는 불과 며칠 만에 크기가 두 배가 되었다.,G0210', '성장/변화 표현', 34);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Main', 'An ugly and dirty lot that people didn’t like has become a pretty garden for everyone.', '사람들이 싫어하던 추하고 더러운 부지가 모두를 위한 예쁜 정원이 되었다.', '현재완료 결과', 35);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Focus In', 'I think chicken is much tastier than sandwiches.', '나는 치킨이 샌드위치보다 훨씬 더 맛있다고 생각한다.', '비교급 강조', 36);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Focus In', 'He couldn’t open the door because he had lost his key.', '그는 열쇠를 잃어버렸었기 때문에 문을 열 수 없었다.', '과거완료 시제', 37);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Grammar', 'Oksig is much cuter than real corn.', '옥식이는 실제 옥수수보다 훨씬 더 귀엽다.', '비교급 강조', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Grammar', 'It is much more beautiful than you think.', '그것은 여러분이 생각하는 것보다 훨씬 더 아름답다.', '비교급 강조', 41);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Listening', 'Thank you for teaching me how to ride a bike.', '자전거 타는 법을 가르쳐 줘서 고마워.', '감사 표현', 28);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (22, 'Main', 'The only way to do it is just to start.', '그것을 하는 유일한 방법은 그냥 시작하는 것이다.', 'to부정사의 명사적 용법', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Listening', 'I’m looking forward to seeing you at the race.', '경주에서 너를 보게 되기를 기대하고 있어.', '기대 표현하기', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Listening', 'I’ll keep my fingers crossed!', '행운을 빌게!', '행운 빌어주기', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Listening', 'I’m really looking forward to the field trip next Tuesday.', '다음 주 화요일 현장 학습이 정말 기대돼.', '기구 표현하기', 47);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Listening', 'Don’t worry. I’m sure you’ll do great.', '걱정하지 마. 네가 잘해낼 거라고 확신해.', '확신 표현하기', 47);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Listening', 'He’s bright enough to make us feel happy.', '그는 우리를 기분 좋게 만들 정도로 똑똑하다.', '형용사 + enough to', 47);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Listening', 'You always make us laugh out loud.', '넌 항상 우리를 크게 웃게 해.', '사역동사', 47);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Main', 'Han Jiwon, a Korean high school student, did research on this topic in 2015.', '한국 고등학생인 한지원은 2015년에 이 주제에 대해 연구를 했다.', '과거 시제 / 어구', 49);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Main', 'Is this research project good enough to win a Nobel Prize?', '이 연구 프로젝트가 노벨상을 받을 만큼 충분히 좋은가?', '형용사 + enough to', 49);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Main', 'The Ig Nobel Prizes are awarded for discoveries that "first make one laugh and then think."', '이그 노벨상은 "먼저 사람들을 웃게 하고 그다음 생각하게 만드는" 발견들에 수여된다.', '수동태 및 주격관계대명사', 49);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Main', 'To save money, the Navy made its sailors shout, “Bang!” instead of using real bombs.', '돈을 아끼기 위해 해군은 선원들이 실제 폭탄을 사용하는 대신 “뱅!”이라고 외치게 했다.', '사역동사 / 어구', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Main', 'He succeeded in floating a live frog in the air by using magnets.', '그는 자석을 사용하여 살아있는 개구리를 공중에 띄우는 데 성공했다.', '어구 표현', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Main', 'If people don’t have a sense of humor, they are usually not very good scientists.', '사람들이 유머 감각이 없다면, 그들은 대개 아주 훌륭한 과학자가 아니다.,G0309', '조건의 접속사', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Main', 'Not only the winners’ fun studies but also the ceremony makes people laugh.', '수상자들의 재미있는 연구뿐만 아니라 시상식도 사람들을 웃게 만든다.', '상관접속사', 51);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Main', ' Zimbabwe''s ten trillion Zimbabwean dollars, which is worth less than one U.S. dollar.', '미화 1달러보다 가치가 낮은 짐바브웨의 10조 달러 지폐.', '계속적 용법의 관계대명사', 51);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Grammar', 'The band is popular enough to win the award.', '그 밴드는 상을 받을 만큼 충분히 인기가 있다.', '형용사 + enough to', 53);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Grammar', 'Anne is not only lovely but also smart.', '앤은 사랑스러울 뿐만 아니라 똑똑하다.', '상관접속사', 53);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Grammar', 'Our songs are easy enough to sing.', '우리 노래는 부르기에 충분히 쉽다.', '형용사 + enough to', 53);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Grammar', 'Your smile is bright enough to light up the classroom.', '네 미소는 교실을 밝힐 만큼 충분히 환하다.', '형용사 + enough to', 57);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Reading', 'Malala Yousafzai won the Nobel Prize because she had fought for children’s rights.', '말랄라 유사프자이는 아동 권리를 위해 싸웠기 때문에 노벨상을 받았다.', '과거완료 시제', 58);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (23, 'Reading', 'Not only Marie Curie but also her daughter was awarded the Nobel Prize.', '마리 퀴리뿐만 아니라 그녀의 딸도 노벨상을 받았다.', '상관접속사', 58);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Listening', 'Why are you disappointed?', '왜 실망했니?', '실망 표현하기', 63);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Listening', 'I failed the audition for the Mapo Youth Band.', '마포 청소년 밴드 오디션에 떨어졌어.', '실패 말하기', 64);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Listening', 'Do you think I should keep trying?', '내가 계속 노력해야 한다고 생각하니?', '조언 구하기', 64);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Listening', 'Sure. Don’t give up. You’ll do better next time.', '물론이지. 포기하지 마. 다음엔 더 잘할 거야.', '격려 표현하기', 64);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Listening', 'My parents won’t let me enter Superstar 101.', '부모님이 내가 슈퍼스타 101에 참가하는 걸 허락하지 않으셔.', '사역동사(let)', 65);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Listening', 'Thank you for your advice.', '조언 고마워.', '감사 표현', 65);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Main', 'It was a movie about three African-American women who worked at NASA.', '그것은 NASA에서 일했던 세 명의 아프리카계 미국인 여성들에 관한 영화였다.', '주격 관계대명사', 67);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Main', 'They dreamed of becoming space experts and tried hard to get over difficulties.', '그들은 우주 전문가가 되는 것을 꿈꿨고 어려움을 극복하기 위해 열심히 노력했다.', '어구 표현', 67);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Main', 'Hearing this', ' I felt really sorry for her.,이 말을 듣고 나는 그녀에 대해 정말 안타까움을 느꼈다.,G0409,분사구문', 'V-ing', 68);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Main', 'This made Al Harrison break down the “Colored Ladies Room” sign.', '이것이 알 해리슨이 "유색인종 여성 전용 화장실" 표지판을 부수게 만들었다.', '사역동사', 68);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Main', 'The judge was impressed by what she said and finally gave her permission.', '판사는 그녀가 한 말에 감명받았고 마침내 그녀에게 허가를 내주었다.', '관계대명사 what', 68);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Main', 'That was what impressed me most in the movie.', '그것이 영화에서 나를 가장 감동시킨 것이었다.', '관계대명사 what', 68);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Main', 'Dorothy studied a new programming language', ' FORTRAN.,도로시는 새로운 프로그래밍 언어인 포트란을 공부했다.,G0411,동격 표현', 'N', 69);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Main', 'Thanks to Dorothy', ' her team members could become programmers.,도로시 덕분에 그녀의 팀원들은 프로그래머가 될 수 있었다.,G0412', '어구 표현', 70);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Main', 'That’s what I need to learn from her.', '그것이 내가 그녀로부터 배워야 할 점이다.', '관계대명사 what', 70);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Main', 'Watching this movie', ' I could learn how to face challenges in life.,이 영화를 보면서 나는 인생의 도전에 맞서는 법을 배울 수 있었다.,G0409,분사구문', 'V-ing', 70);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Focus In', 'Walking on the street', ' he looked at the map.,길을 걸으면서 그는 지도를 보았다.,G0409,분사구문', 'V-ing', 71);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Focus In', 'That’s exactly what I want.', '그것이 정확히 내가 원하는 것이다.', '관계대명사 what', 71);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Grammar', 'I love what I do. I feel proud', ' seeing people enjoy my dishes., 나는 내가 하는 일을 사랑한다. 사람들이 내 요리를 즐기는 것을 보며 자부심을 느낀다.,G0410', '관계대명사 what / 분사구문', 76);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (24, 'Listening', 'Do you think I should study harder for my future?', '내가 미래를 위해 공부를 더 열심히 해야 한다고 생각하니?', '조언 구하기', 64);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Listening', 'I’m curious about sign language. What does it mean?', '나는 수화에 대해 궁금해. 그것은 무엇을 의미하니?', '관심 표현 및 의미 묻기', 88);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Listening', 'It means “Hello”.', '그것은 “안녕”을 의미해.', '의미 설명하기', 88);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Listening', 'What does this sign mean? It means you must not ride a bike here.', '이 표지판은 무엇을 의미하니? 여기서 자전거를 타면 안 된다는 뜻이야.', '의미 묻기 및 금지하기', 88);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Listening', 'This house is famous for having thousands of secrets in it.', '이 집은 수천 개의 비밀을 간직하고 있는 것으로 유명하다.', '어구 표현', 89);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'Speaking to family in a foreign country is rather easy and simple today.', '오늘날 외국에 있는 가족에게 말하는 것은 꽤 쉽고 간단하다.', '동명사 주어', 91);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'At the time, more than 5% of the people in Italy could not read or write.', '당시에 이탈리아 인구의 5% 이상이 읽거나 쓸 줄 몰랐다.', '수량 표현', 91);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'My dear love', ' I miss you so much, and I reach my arms out toward you.,사랑하는 당신, 당신이 정말 보고 싶어서 당신을 향해 팔을 뻗어 봅니다.,G0507', '감정 표현', 92);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'If I got a letter from you', ' I would be very happy.,당신에게서 편지를 받는다면 정말 행복할 거예요.,G0508,가정법 과거', 'If + S + 과거동사', 92);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'Your mother fell ill and I’m going to visit her in the hospital.', '당신의 어머니께서 병환이 나셔서 제가 병원에 면회를 가려고 합니다.', '어구 표현', 92);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'I’ll go there with our middle son while the oldest looks after the youngest.', '첫째가 막내를 돌보는 동안 나는 둘째 아들과 그곳에 가겠습니다.', '시간의 접속사 while', 92);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'I hired a man whose sons are good workers.', '나는 아들들이 일을 잘하는 한 남자를 고용했습니다.', '소유격 관계대명사', 93);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'I got enough oil to fill a large pot and a small one.', '나는 큰 단지와 작은 단지를 채울 만큼 충분한 기름을 얻었습니다.', '형용사/부사 수식', 93);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'But whether one or the other wins', ' it’s the same.,그러나 이쪽이 이기든 저쪽이 이기든 그것은 마찬가지입니다.,G0513', '접속사 whether', 93);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'I would be so happy if you were with me.', '당신이 나와 함께 있다면 정말 행복할 거예요.,G0508,가정법 과거', 'If + S + were', 94);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Main', 'It was written in 1973 by a woman whose husband was far away.', '그것은 남편이 멀리 떨어져 있던 한 여인에 의해 1973년에 쓰였다.', '소유격 관계대명사', 91);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Grammar', 'Pictures speak a thousand words', ' you know.,알다시피 그림은 천 마디 말보다 더 많은 것을 전달하죠.,G0514', '격언 표현', 89);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Focus In', 'Lala is the girl whose dog wants a hot dog.', '라라는 개가 핫도그를 원하는 소녀이다.', '소유격 관계대명사', 95);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Focus In', 'If I had wings', ' I would fly in the sky.,나에게 날개가 있다면 하늘을 날 수 있을 텐데.,G0508,가정법 과거', 'If + S + had', 95);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Focus In', 'If I were a bird', ' I would fly to Busan to meet my friend.,내가 새라면 친구를 만나러 부산으로 날아갈 텐데.,G0508,가정법 과거', 'If + S + were', 96);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (25, 'Focus In', 'The animal whose neck is long is a giraffe.', '목이 긴 동물은 기린이다.', '소유격 관계대명사', 96);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Listening', 'Which do you prefer, pandas or cats? I prefer pandas.', '판다와 고양이 중 어떤 것을 더 선호하니? 나는 판다를 더 좋아해.,G0601,선호 묻고 답하기', 'Which do you prefer', 106);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Listening', 'Which do you prefer, working alone or working on a team?', '혼자 일하는 것과 팀으로 일하는 것 중 무엇을 더 선호하니?,G0601,선호 묻기', 'Which do you prefer', 106);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Listening', 'Actually', ' I hate working on a team.,사실, 나는 팀으로 일하는 것을 정말 싫어해.,G0602,강한 불호 표현', 'Actually', 106);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Listening', 'Which do you prefer, paper books or digital books? I prefer digital books.', '종이책과 전자책 중 어떤 것을 더 선호하니? 나는 전자책이 좋아.,G0601,선호 묻고 답하기', 'Which do you prefer', 106);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Listening', 'I’m proud that we’ve collected so many interesting books to give away.', '나눠줄 흥미로운 책들을 이렇게 많이 모아서 뿌듯해.', '감정의 원인(접속사)', 107);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Listening', 'Which do you prefer', ' making the bookmarks or writing the messages?,책갈피를 만드는 것과 메시지를 쓰는 것 중 어떤 걸 더 하고 싶니?,G0601,선호 묻기', 'Which do you prefer', 107);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Main', 'The more books we share', ' the more we learn.,우리가 더 많은 책을 공유할수록, 우리는 더 많이 배운다.,G0604,the + 비교급', 'the + 비교급', 110);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Main', 'It provides both the information and the tools necessary to make clean drinking water.', '이것은 깨끗한 식수를 만드는 데 필요한 정보와 도구를 모두 제공한다.', '상관접속사', 111);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Main', 'It is this filtered water that you can drink.', '당신이 마실 수 있는 것은 바로 이 여과된 물이다.', 'It ~ that 강조구문', 111);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Main', 'This amazing book saves the lives of many children from diseases that come from dirty water.', '이 놀라운 책은 더러운 물에서 기인하는 질병으로부터 많은 아이의 생명을 구한다.', '주격 관계대명사', 111);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Main', 'It is these tiny seeds that change the book into a tree.', '그 책을 나무로 변화시키는 것은 바로 이 작은 씨앗들이다.', 'It ~ that 강조구문', 112);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Main', 'The bigger your imagination is', ' the more wonderful your books will become.,여러분의 상상력이 클수록, 여러분의 책은 더 멋지게 변할 것이다.,G0604,the + 비교급', 'the + 비교급', 112);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Focus In', 'The higher we go up', ' the farther we see.,우리가 더 높이 올라갈수록, 우리는 더 멀리 본다.,G0604,the + 비교급', 'the + 비교급', 113);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Focus In', 'The deeper we go under the sea', ' the darker it gets.,우리가 바다 깊이 들어갈수록, 더 어두워진다.,G0604,the + 비교급', 'the + 비교급', 113);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Focus In', 'It was Team Kim that beat the Canadian team in Gangneung in 2018.', '2018년 강릉에서 캐나다 팀을 이긴 것은 바로 팀 킴이었다.', 'It ~ that 강조구문', 113);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Focus In', 'It is the class field trip that I won’t forget.', '내가 잊지 못할 것은 바로 학급 현장 체험 학습이다.', 'It ~ that 강조구문', 114);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Grammar', 'The lighter the drone is', ' the longer it flies.,드론이 더 가벼울수록, 더 오래 난다.,G0604,the + 비교급', 'the + 비교급', 116);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Grammar', 'The longer the tail is', ' the better it flies.,꼬리가 더 길수록, 더 잘 난다.,G0604,the + 비교급', 'the + 비교급', 116);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Main', 'Register your book online and get an ID number.', '책을 온라인에 등록하고 ID 번호를 받으세요.', '명령문 + and', 110);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (26, 'Main', 'As the water goes through the page', ' it changes into clean drinking water.,물이 페이지를 통과하면서 깨끗한 식수로 바뀐다.,G0608', '접속사 as', 111);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Listening', 'How do you feel about this drama?', '이 드라마에 대해 어떻게 생각하니?', '의견 묻기', 123);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Listening', 'I think it looks touching.', '내 생각엔 감동적인 것 같아.', '의견 말하기(감각동사)', 123);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Listening', 'I don’t agree with you. It looks boring.', '난 네 의견에 동의하지 않아. 지루해 보여.', '반대하기', 124);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Listening', 'I think it’s great. It shows the phone is strong.', '그거 멋진 것 같아. 전화기가 튼튼하다는 걸 보여주잖아.', '의견 말하기', 124);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Listening', 'How do you feel about Big Mouth’s Show?', '빅 마우스 쇼에 대해 어떻게 생각하니?', '의견 묻기', 125);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Listening', 'I don’t think he’s lying. It’s a great photo.', '난 그가 거짓말을 하고 있다고 생각지 않아. 멋진 사진이야.', '부정적 의견/추측', 125);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Listening', 'An octopus can’t live out of the sea.', '문어는 바다 밖에서 살 수 없어.', '강한 부정적 추측', 125);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Main', 'The stories were actually made by teenagers, not by major newspapers.', '그 이야기들은 주요 신문사가 아니라 사실은 십 대들에 의해 만들어졌다.', '수동태', 127);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Main', 'The story turned out to be a complete lie.', '그 이야기는 완전한 거짓말로 드러났다.', '어구 표현', 127);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Main', 'It’s really important to look at the right sources and to pay attention to what is real.', '올바른 출처를 보고 무엇이 진짜인지 주의를 기울이는 것이 정말 중요하다.', '가주어 it / 어구', 128);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Main', 'Check if the news has hard evidence.', '그 뉴스가 확실한 증거를 가지고 있는지 확인해라.', '접속사 if (~인지 아닌지)', 128);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Main', 'Garcia-Fuller’s students also learn how to tell fact from opinion in the news.', '가르시아 풀러의 학생들은 또한 뉴스에서 사실과 의견을 구별하는 법을 배운다.', '어구 표현', 129);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Main', 'You also have to check if they are based on facts.', '당신은 또한 그것들이 사실에 근거하고 있는지 확인해야 한다.', '접속사 if (~인지 아닌지)', 129);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Main', 'If a story or a photo seems too good to be true', ' stop and think.,만약 이야기나 사진이 믿기기 힘들 정도로 너무 좋다면, 멈춰서 생각해 보라.,G0711', '너무 ~해서 ~할수 없다', 129);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Main', 'The site is full of information on an animal called a tree octopus.', '그 사이트는 나무 문어라고 불리는 동물에 대한 정보로 가득 차 있다.', '어휘 및 수식', 130);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Main', 'Question everything, even things that I say.', '모든 것에 의문을 가져라, 심지어 내가 말하는 것들까지도.,G0713', '주격 관계대명사', 130);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Focus In', 'Garcia-Fuller said she was teaching her students how to tell fake news from real news.', '가르시아 풀러는 자신이 학생들에게 가짜 뉴스와 진짜 뉴스를 구별하는 법을 가르치고 있다고 말했다.', '간접 화법(전달동사)', 131);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Focus In', 'I wonder if she will like my present.', '그녀가 내 선물을 좋아할지 궁금해.', '접속사 if (~인지 아닌지)', 131);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Focus In', 'She told her brother that she was not crying.', '그녀는 남동생에게 울고 있지 않다고 말했다.', '간접 화법(전달동사)', 131);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (27, 'Focus In', 'He said that he knew the answer.', '그는 자신이 정답을 알고 있다고 말했다.', '간접 화법(전달동사)', 132);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Listening', 'I can’t stand it. The music is too noisy.', '더 이상 못 참겠어. 음악 소리가 너무 시끄러워.', '불평 표현하기', 142);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Listening', 'Calm down! They’re having a birthday party.', '진정해! 그들은 생일 파티를 하고 있잖아.', '진정시키기', 142);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Listening', 'They are talking too loudly. I can’t stand it.', '저 사람들이 너무 크게 이야기해서 참을 수가 없어.', '불평 표현하기', 142);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Listening', 'Calm down! They are very old. They can’t hear well.', '진정해! 저분들은 연세가 많으셔서 잘 들리지 않으시는 거야.', '진정시키기', 142);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Listening', 'Science is too difficult for me. I don’t think I can finish my homework today.', '과학은 나에게 너무 어려워. 오늘 숙제를 다 끝낼 수 있을 것 같지 않아.', '상태 및 추측', 143);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Listening', 'Why didn’t you do the dishes? I can’t stand it.', '왜 설거지를 안 했니? 정말 못 참겠어.', '불평 표현하기', 143);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Listening', 'What’s that noise outside? I can’t stand it.', '밖의 저 소음은 뭐야? 정말 견딜 수가 없어.', '불평 표현하기', 144);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Main', 'You’re the strongest man in my army', ' but you have much to learn.,너는 내 군대에서 가장 강한 자이지만, 아직 배울 것이 많다.,G0804', '형용사 수식(to부정사)', 145);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Main', 'The king ordered Corky to go to a famous military school.', '왕은 코키에게 유명한 군사 학교에 가라고 명령했다.', '5형식 문장(order)', 145);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Main', 'Patience is the most important thing to win a war.', '인내는 전쟁에서 이기기 위한 가장 중요한 조건이다.', '최상급 표현', 145);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Main', 'Some gave Corky angry looks', ' and others shouted at him.,어떤 사람들은 코키를 화난 눈으로 쳐다보았고, 다른 사람들은 그에게 소리를 질렀다.,G0807,부정대명사(Some/Others)', 'Some ...', 146);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Main', 'Soft words are stronger than sharp swords.', '부드러운 말은 날카로운 칼보다 더 강하다.', '비교급 표현', 146);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Main', 'The first one to sit in the chair will be the winner.', '의자에 먼저 앉는 사람이 승자가 될 것이다.', '명사 수식(to부정사)', 147);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Main', 'Instead', ' I will take care of the injured.,그 대신에, 나는 부상자들을 돌보겠습니다.,G0810', '어구 표현', 147);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Main', 'Of all the great weapons', ' peace is my favorite.,모든 위대한 무기들 중에서 평화가 내가 가장 좋아하는 것이다.,G0811', '최상급의 범위', 148);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Grammar', 'One is flying', ' and the other is sitting on the tree.,한 마리는 날고 있고, 다른 한 마리는 나무 위에 앉아 있다.,G0807,부정대명사(One/The other)', 'One ...', 149);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Grammar', 'Some are making snowmen', ' and others are playing with snowballs.,어떤 사람들은 눈사람을 만들고 있고, 다른 사람들은 눈싸움을 하고 있다.,G0807,부정대명사(Some/Others)', 'Some ...', 149);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Grammar', 'The woman told the boy to be careful.', '여자는 소년에게 조심하라고 말했다.', '5형식 문장(tell)', 150);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Grammar', 'The man ordered the dog to get the ball.', '남자는 개에게 공을 가져오라고 명령했다.', '5형식 문장(order)', 150);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (28, 'Grammar', 'We need 두 things for peace. One is love. The other is hope.', '평화를 위해 우리에게는 두 가지가 필요합니다. 하나는 사랑이고, 다른 하나는 희망입니다.,G0807', '부정대명사(One/The other)', 153);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'What makes you happy?', '무엇이 너를 행복하게 하니?', '5형식 사역동사', 12);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I’m happy when I listen to music.', '나는 음악을 들을 때 행복해.', '시간의 접속사', 12);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I’m glad we can have dinner together.', '우리가 함께 저녁을 먹을 수 있어서 기뻐.', '감정의 원인(접속사)', 13);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I’m glad we’re in the same class.', '우리가 같은 반이 되어서 기뻐.', '감정의 원인(접속사)', 13);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I agree with you. The food looks so delicious.', '네 말에 동의해. 음식이 정말 맛있어 보여.', '동의 공식 및 감각동사', 13);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'You can say that again.', '전적으로 동의해. (네 말이 맞아.)', '강한 동의 표현', 14);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I don’t agree with you on that issue.', '그 문제에 대해서는 너와 의견이 달라.', '의견 불일치 표현', 14);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'That red phone case looks nice!', '저 빨간색 휴대폰 케이스 멋진데!', '감각동사', 15);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'You can say that again! Mom would love it.', '정말 그래! 엄마께서 좋아하실 거야.', '강한 동의 표현', 15);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'It costs 40,000 won. That’s so expensive!', '4만 원이야. 너무 비싸다!', '가격 및 상태 표현', 15);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I don’t agree. Look! It works as a wallet, too.', '난 그렇게 생각하지 않아. 봐! 지갑 기능도 하잖아.', '의견 불일치 표현', 15);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I’m delighted to buy something special for Mom.', '엄마를 위해 특별한 것을 살 수 있어서 기뻐.', '감정의 원인(to부정사)', 15);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'Antonio went to different places to support his family by trading.', '안토니오는 무역을 통해 가족을 부양하기 위해 여러 장소를 다녔다.', 'to부정사의 부사적 용법', 16);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'One day, he visited a faraway island. There he traded tools for spices.', '어느 날, 그는 먼 섬을 방문했다. 그곳에서 그는 도구를 향신료와 맞바꿨다.', '전치사 구문 (trade A for B)', 16);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'Thanks to Antonio, the islanders could get what they needed.', '안토니오 덕분에 섬사람들은 자신들이 필요한 것을 얻을 수 있었다.', '관계대명사 what', 17);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'Antonio was surprised that there were rats in the palace.', '안토니오는 궁전에 쥐들이 있는 것을 보고 매우 놀랐다.', '감정의 원인(접속사)', 17);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'What the islanders here need is not tools or books, but cats.', '여기 섬사람들에게 필요한 것은 도구나 책이 아니라 고양이다.', '관계대명사 what', 17);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'The queen gave Antonio a chest that was filled with jewels.', '여왕은 안토니오에게 보석으로 가득 찬 상자를 주었다.', '주격 관계대명사', 18);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'Luigi, the richest merchant, was jealous. “Cats are worthless,” Luigi thought.', '가장 부유한 상인인 루이지는 질투가 났다. "고양이는 가치가 없어"라고 루이지는 생각했다.', '최상급 및 보어', 19);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'Luigi packed his ship with wonderful paintings. He expected more jewels.', '루이지는 배에 멋진 그림들을 실었다. 그는 더 많은 보석을 기대했다.', '동사 구문 (pack A with B)', 19);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'When Luigi opened the box, he was speechless. There was a kitten.', '루이지가 상자를 열었을 때, 그는 할 말을 잃었다. 그 안에는 아기 고양이가 있었다.', '시간의 접속사', 19);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'Luigi did not return home a richer man. But he was surely a wiser one.', '루이지는 더 부유한 사람이 되어 돌아오지는 못했다. 하지만 그는 확실히 더 현명한 사람이 되었다.', '비교급', 19);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'That’s what I want to show you.', '그것이 내가 당신에게 보여주고 싶은 것이다.', '관계대명사 what', 52);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Main', 'We often see Plum move in the dark.', '우리는 종종 플럼이 어둠 속에서 움직이는 것을 본다.', '5형식 지각동사', 20);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Reading', 'What makes you happy?', '무엇이 여러분을 행복하게 하나요?', '5형식 사역동사 / 시간 접속사', 36-39);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Reading', 'Here are the results of our survey on the 100 students of our school.', '여기 우리 학교 학생 100명을 대상으로 한 설문 조사 결과가 있습니다.', '5형식 사역동사 / 시간 접속사', 36-39);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Reading', 'Most students said they feel happy when they are with their friends.', '대부분의 학생은 친구들과 함께 있을 때 행복을 느낀다고 답했습니다.', '5형식 사역동사 / 시간 접속사', 36-39);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Reading', 'I visited a local hospital last Sunday to help children.', '나는 지난주 일요일에 아이들을 돕기 위해 지역 병원을 방문했습니다.', '지각동사 / 관계대명사 what', 45-52);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Reading', 'While I was there, I saw some people helping each other.', '그곳에 있는 동안, 나는 사람들이 서로 돕고 있는 것을 보았습니다.', '지각동사 / 관계대명사 what', 45-52);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Reading', 'That’s what I want to show you today.', '그것이 오늘 내가 여러분께 보여드리고 싶은 것입니다.', '지각동사 / 관계대명사 what', 45-52);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'How are you feeling today?', '오늘 기분이 어떠니?', '감격/감정 표현하기', 12-14);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I’m happier than ever.', '그 어느 때보다 행복해.', '감격/감정 표현하기', 12-14);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I finally booked four tickets for the concert!', '마침내 콘서트 티켓 4장을 예매했거든!', '감격/감정 표현하기', 12-14);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I’m glad to hear that.', '그 소리를 들으니 기쁘구나.', '감격/감정 표현하기', 12-14);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Listening', 'I’m looking forward to it.', '정말 기대된다.', '감격/감정 표현하기', 12-14);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Vocabulary', 'Why did you look so nervous yesterday?', '어제 왜 그렇게 긴장한 것처럼 보였니?', '감각동사 / 원인의 접속사', 16-18);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Vocabulary', 'I was nervous because I had a big English test.', '영어 큰 시험이 있어서 긴장했었어.', '감각동사 / 원인의 접속사', 16-18);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (11, 'Vocabulary', 'But it’s over now, so I feel great!', '하지만 이제 다 끝났어, 그래서 기분이 정말 좋아!', '감각동사 / 원인의 접속사', 16-18);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Listening', 'Though it was hard, I felt proud.', '비록 힘들었지만, 나는 보람을 느꼈어.', '양보의 접속사(though)', 34);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Vocabulary', 'The broken chair was fixed by my dad.', '부러진 의자는 아빠에 의해 수리되었다.', '과거분사의 명사 수식', 36);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Main', 'The man sitting under the tree is my uncle.', '나무 아래에 앉아 있는 남자는 나의 삼촌이다.', '현재분사의 명사 수식', 38);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Main', 'Though he is old, he is very active.', '비록 그는 연세가 많으시지만, 매우 활동적이시다.', '양보의 접속사(though)', 44);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Reading', 'The girl reading a book in the corner is Nari.', '구석에서 책을 읽고 있는 소녀는 나리이다.', '현재분사의 명사 수식', 60);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Reading', 'The man sitting under the tree is my uncle.', '나무 아래에 앉아 있는 남자는 저의 삼촌입니다.', '현재분사 수식 / 양보의 접속사', 38-44);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Reading', 'Though he is old, he is very active.', '비록 그는 연세가 많으시지만, 매우 활동적이십니다.', '현재분사 수식 / 양보의 접속사', 38-44);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Reading', 'He used to be a soccer player.', '그는 축구 선수였습니다.', '현재분사 수식 / 양보의 접속사', 38-44);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Listen and Answer +Question What will the speakers do in the afternoon?', '듣고 대답하기 +질문 발표자들은 오후에 무엇을 할 예정인가요?', '의문사 구문 / 조동사', 31);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Save the A rctic  in D anger /T_h  e Songji Times ’s Future Listen again and complete.', 'Save the Arctic in Danger /T_h e 송지타임즈의 미래 다시 듣고 완성해 보세요.', '비교급', 32);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'The program about endangered animals was interesting.', '멸종위기 동물에 관한 프로그램이 흥미로웠어요.', '현재분사/동명사', 32);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'The photograph of the insects was unbelievable.', '곤충 사진은 믿을 수 없을 정도였습니다.', '일반 문장', 32);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'B Ice cream is more delicious, I think.', 'B 내 생각엔 아이스크림이 더 맛있는 것 같아.', '비교급', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'A Which do you prefer to take, the bus or the subway?', 'A 버스와 지하철 중 어느 것을 타는 것을 선호하시나요?', 'to부정사 / 관계대명사', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'B I prefer to take the subway every weekday.', 'B 나는 평일마다 지하철을 타는 걸 더 좋아해요.', 'to부정사 / 비교급', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Which Do You Like Better?', '어느 것이 더 마음에 드나요?', '관계대명사 / 비교급', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I like dogs better.', '나는 개가 더 좋다.', '비교급', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'They are more friendly.', '그들은 더 친절합니다.', '비교급', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I like cats better.', '저는 고양이를 더 좋아해요.', '비교급', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Cats are much cleaner than dogs.', '고양이는 개보다 훨씬 깨끗합니다.', '비교급', 33);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'My dream is to make a fantastic team.', '내 꿈은 환상적인 팀을 만드는 것이다.', 'to부정사 / 사역동사', 34);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'A Can you tell me about your plan?', 'A 당신의 계획에 대해 말씀해주실 수 있나요?', '조동사', 34);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I’ll tell you as soon as I can.', '최대한 빨리 말씀드리겠습니다.', '이유의 접속사 / 시간의 접속사', 34);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Can You Tell Me More About It?', '그것에 대해 더 말해주실 수 있나요?', '조동사 / 비교급', 34);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'It''s a big animal that has a long nose and big ears.', '긴 코와 큰 귀를 가진 큰 동물입니다.', '접속사/관계대명사 that', 34);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'What''s an elephant?', '코끼리는 무엇입니까?', '의문사 구문', 34);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'There‛s lots of trash in the sea.', '바다에는 쓰레기가 많아요.', '일반 문장', 35);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Many whales eat it and get sick.', '많은 고래들이 그것을 먹고 병에 걸립니다.', '일반 문장', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Is there anything we can do to help them?', '그들을 돕기 위해 우리가 할 수 있는 일이 있나요?', 'to부정사 / 조동사', 35);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'First, we should try to clean up the sea.', '첫째, 바다를 깨끗하게 만드는 노력을 해야 합니다.', 'to부정사 / 조동사', 35);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Present and share.', '발표하고 공유하세요.', '일반 문장', 35);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Many whales eat it and Sure.', '많은 고래가 그것을 먹습니다. 물론이죠.', '일반 문장', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Many whales eat it and That‛s too bad.', '많은 고래들이 그것을 먹는데 안타깝습니다.', '접속사/관계대명사 that', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I heard whales are having a hard time these days.', '요즘 고래들이 힘들다고 들었어요.', '현재분사/동명사', 35);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Listen and number.', '듣고 번호를 매기세요.', '비교급', 35);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'uestion Box Bees live together in a colony.', '상자벌은 군체를 이루어 함께 생활합니다.', '비교급', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'It usually has a large number of residents in it.', '일반적으로 그 안에는 많은 수의 거주자가 있습니다.', '비교급', 36);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Elephants are social animals.', '코끼리는 사회적 동물입니다.', '일반 문장', 36);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Female elephants help each other look after their babies.', '암컷 코끼리는 서로 새끼를 돌보는 것을 돕습니다.', '시간의 접속사 / 비교급', 36);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Dogs are more sensitive to smells than humans are.', '개는 사람보다 냄새에 더 민감합니다.', 'to부정사 / 비교급', 36);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Animals often rub against trees to keep insects oﬀ   their bodies.', '동물은 종종 벌레가 몸에 닿지 않도록 나무에 문지릅니다.', 'to부정사', 36);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Can you guess what they are?', '그것들이 무엇인지 추측할 수 있나요?', '의문사 구문 / 조동사', 38);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Yes, the answer is ants.', '네, 답은 개미입니다.', '비교급', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'We want to share with you what we have learned about these insects.', '우리는 이 곤충에 관해 우리가 배운 것을 여러분과 공유하고 싶습니다.', '완료시제 / to부정사', 38);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'We often see ants come out of nowhere.', '우리는 개미가 갑자기 나타나는 것을 종종 봅니다.', '지각동사', 39);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Like humans, they live almost everywhere in the world, except a few extremely cold places including Antarctica.', '인간과 마찬가지로 그들은 남극 대륙을 포함하여 극도로 추운 몇몇 지역을 제외하고 전 세계 거의 모든 곳에 살고 있습니다.', '현재분사/동명사', 39);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'As of 2018, there were over 7 billion people on Earth.', '2018년 기준으로 지구상의 인구는 70억 명이 넘었습니다.', '이유의 접속사 / 비교급', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Then, how about ants?', '그렇다면 개미는 어떻습니까?', '의문사 구문', 39);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'According to scientists, there are about one million ants for every human in the world.', '과학자들에 따르면, 전 세계에는 인간 한 명당 약 백만 마리의 개미가 있다고 합니다.', 'to부정사 / 현재분사/동명사', 39);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Though each ant hardly weighs anything, one million ants are as heavy as a human being weighing about 62 kilograms.', '개미 한 마리의 무게는 거의 없지만, 백만 마리의 개미는 약 62kg의 인간 무게만큼 무겁습니다.', '양보의 접속사 / 이유의 접속사', 39);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '02 Some ants can carry things that are 50 times their own body weight.', '02 어떤 개미들은 자기 몸무게의 50배나 되는 물건을 옮길 수 있어요.', '접속사/관계대명사 that / 조동사', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '04 An ant has two stomachs.', '04 개미는 위가 두 개 있어요.', '일반 문장', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'One stomach holds food for itself, and the other holds food to share with others.', '한 위는 스스로 음식을 담고 있고, 다른 위는 다른 사람과 나누어 먹을 음식을 담고 있습니다.', 'to부정사 / 비교급', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '05 Most ants can swim and live 24 hours underwater.', '05 대부분의 개미는 헤엄을 칠 수 있고 물 속에서 24시간 동안 살아갈 수 있습니다.', '조동사 / 비교급', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '03 Ants do not have lungs but breathe through small holes in their bodies.', '03 개미는 폐가 없지만 몸에 있는 작은 구멍으로 숨을 쉰다.', '사역동사', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Ants live in colonies which have lots of residents living together.', '개미는 많은 주민이 함께 생활하는 군집을 이루고 살아요.', '관계대명사 / 현재분사/동명사', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Within a colony, there are usually three different types of ants.', '군체 내에는 일반적으로 세 가지 유형의 개미가 있습니다.', '일반 문장', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'There is the queen, and what she does her entire life is lay eggs.', '여왕벌이 있는데, 여왕벌이 평생 하는 일은 알을 낳는 것입니다.', '의문사 구문 / 비교급', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'The second type of ant is the male that helps the queen produce these eggs.', '두 번째 유형의 개미는 여왕개미가 알을 생산하도록 돕는 수컷입니다.', '접속사/관계대명사 that', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'The third type of ant is the worker.', '세 번째 유형의 개미는 일개미입니다.', '비교급', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Worker ants are all female and do very important jobs, like caring for eggs, defending the colony, and collecting food.', '일개미는 모두 암컷이며 알을 돌보고, 군체를 방어하고, 식량을 모으는 등 매우 중요한 일을 합니다.', '현재분사/동명사 / 비교급', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'What Is the Ant Society Like?', '개미사회는 어떤가요?', '의문사 구문', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Though ants do not speak like humans, they actually have a “language.', '개미는 인간처럼 말하지는 않지만 실제로는 ''언어''를 가지고 있습니다.', '양보의 접속사', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '” Ants produce a chemical called a pheromone to communicate with one another.', '개미는 페로몬이라는 화학물질을 생산해 서로 소통한다.', 'to부정사 / 비교급', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'By using the chemical, they can exchange information about food or danger.', '화학물질을 사용함으로써 그들은 음식이나 위험에 대한 정보를 교환할 수 있습니다.', '조동사 / 현재분사/동명사', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Ants also use touch for communication.', '개미는 또한 의사소통을 위해 접촉을 사용합니다.', '일반 문장', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'For example, if an ant fi  nds food, it passes on the good news by rubbing its body on its neighbor.', '예를 들어, 개미가 먹이를 찾으면 이웃에게 몸을 비비면서 좋은 소식을 전합니다.', '조건의 접속사 / 현재분사/동명사', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Since an ant has legs covered with very sensitive hairs, it can sense even the smallest touch.', '개미는 매우 민감한 털로 덮여 있는 다리를 가지고 있기 때문에 아주 작은 접촉이라도 감지할 수 있습니다.', '이유의 접속사 / 조동사', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'How Do Ants Communicate?', '개미는 어떻게 의사소통을 하나요?', '의문사 구문', 40);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Ants don’t live in Antarctica.', '개미는 남극 대륙에 살지 않습니다.', '일반 문장', 41);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'T F Number There are about one ants for every human in the world.', 'T F 숫자 세상에는 인간 한 명당 개미 한 마리 정도가 있습니다.', '비교급', 41);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Society Ants live in a(n) .', '사회 개미는 a(n) 에 살고 있습니다.', '일반 문장', 41);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'It usually has diﬀ  erent types of ants.', '일반적으로 다양한 종류의 개미가 있습니다.', '일반 문장', 41);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Communication Ants use a special and the sense of TBZJOHTBCPVUJOTFDUT Connect to Culture TBZJOHTBCPVUJOTFDUT TBZJOHTBCPVUJOTFDUT TBZJOHTBCPVUJOTFDUT t&WFOBOBOUDBOIVSUBOFMFQIBOUu (SFFDF Male ants defend the colony.', '의사소통 개미는 특별한 의미와 감각을 사용합니다. TBZJOHT BCPVU JOTFDUT 문화에 연결 TBZJOHT BCPVU JOTFDUT TBZJOHT BCPVU JOTFDUT TBZJOHT BCPVU JOTFDUT t&WFO BO BOU DBO IVSU BO FMFQIBOU u (SFFDF 수컷 개미는 식민지를 방어합니다.', 'to부정사', 41);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'T F Ants’ legs are covered with sensitive hairs.', 'T F 개미의 다리는 민감한 털로 덮여 있습니다.', '수동태', 41);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'T F Ants use their lungs to breathe.', 'T F 개미는 숨을 쉬기 위해 폐를 사용합니다.', 'to부정사', 41);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'T F Worker ants are all male and do many kinds of jobs in a colony.', 'T F 일개미는 모두 수컷이며 군체에서 다양한 종류의 일을 합니다.', '비교급', 41);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Food Collection Honeybees visit to collect food.', '음식 수집 꿀벌은 음식을 수집하기 위해 방문합니다.', 'to부정사', 42);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Home Honeybees are found in warm places around the world.', '홈 꿀벌은 전 세계의 따뜻한 곳에서 발견됩니다.', '일반 문장', 42);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Fun Facts •      A worker bee makes hundreds of trips to produce a small amount of •   By moving around, honeybees help plants Search and take notes.', '재미있는 사실 • 일벌은 소량의 양을 생산하기 위해 수백 번 이동합니다. • 꿀벌은 돌아다니면서 식물을 검색하고 기록하는 데 도움을 줍니다.', 'to부정사 / 현재분사/동명사', 42);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Look at the sun rising over the sea.', '바다 위로 떠오르는 태양을 보세요.', '현재분사/동명사 / 비교급', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'the picture painted by a parrot.', '앵무새가 그린 그림.', '일반 문장', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I take care of street cats since they need help.', '나는 길고양이를 돌본다. 도움이 필요하기 때문이다.', '이유의 접속사', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Though the trains were on time.', '기차가 정시에 도착했지만.', '양보의 접속사', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'run painttake sitmake It is hot.', '페인트테이크 sitmake를 실행하세요. 정말 뜨겁습니다.', '일반 문장', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I ate a whole pizza.', '피자 한판을 다 먹었습니다.', '일반 문장', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I am a middle school student.', '저는 중학생입니다.', '일반 문장', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'This is a picture last weekend.', '지난 주말 사진이에요.', '일반 문장', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I visited a pet shop by Aunt Mary.', '나는 메리 이모가 운영하는 애완동물 가게를 방문했습니다.', '일반 문장', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I helped her clean the snake cage of glass.', '나는 그녀가 유리로 만든 뱀 우리를 청소하는 것을 도왔습니다.', '비교급', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'The woman the snake is Aunt Mary.', '뱀이라는 여자는 메리 이모입니다.', '일반 문장', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'The parrot on the tree said, “Hurry up.', '나무 위의 앵무새가 말했습니다. “서둘러요.', '일반 문장', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '”  The cat watched us from a chair green and blue.', '” 고양이는 녹색과 파란색의 의자에 앉아 우리를 지켜보았습니다.', '일반 문장', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Can you give me a hand?', '나에게 도움을 줄 수 있나요?', '조동사', 44);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'He shouted at the top of his lungs.', '그는 목청껏 소리쳤다.', '일반 문장', 44);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'He often tells people things that are secrets.', '그는 사람들에게 비밀스러운 것을 자주 이야기합니다.', '접속사/관계대명사 that', 44);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Guess the animal that I have in mind.', '내가 생각하는 동물을 맞춰보세요.', '접속사/관계대명사 that / 사역동사', 45);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'It lives in Australia.', '호주에 산다.', '일반 문장', 45);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Its name starts with K.', '이름은 K로 시작합니다.', '일반 문장', 45);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'female entire breathe extremely 1  Most of the club members are 2  Th  e air was so fresh, and the hikers started to slowly.', '여성 전체 호흡이 극도로 1 동아리 회원 대부분이 2 명입니다. 공기가 너무 신선해서 등산객들이 천천히 걷기 시작했습니다.', 'to부정사 / 최상급', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '3    I had few friends in elementary school since I was shy.', '3 나는 수줍음이 많아서 초등학교 때 친구가 거의 없었다.', '이유의 접속사', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '4  Mother Teresa spent her life looking aft  er the poor.', '4 테레사 수녀는 가난한 사람들을 돌보며 일생을 보냈습니다.', '현재분사/동명사 / 비교급', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'LISTENING & SPEAKING Listen and role play.', '듣기 및 말하기 듣기와 역할극을 해보세요.', '현재분사/동명사', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'READING Read and answer.', '읽기 읽고 대답하세요.', '현재분사/동명사 / 비교급', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Ants seem to be busy all the time and never rest.', '개미는 항상 바쁘고 절대 쉬지 않는 것 같습니다.', 'to부정사 / 비교급', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'But this is not true.', '그러나 이것은 사실이 아니다.', '일반 문장', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Worker ants rest by taking very short naps about 250 times a day.', '일개미는 하루에 약 250번 정도 아주 짧은 낮잠을 자면서 휴식을 취합니다.', '현재분사/동명사 / 비교급', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Each of these naps lasts only about a minute.', '각각의 낮잠은 약 1분 정도만 지속됩니다.', '일반 문장', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'This means that the worker ants sleep for about four hours each day.', '이것은 일개미가 매일 약 4시간 동안 잠을 잔다는 것을 의미합니다.', '접속사/관계대명사 that / 비교급', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'On the other hand, queen ants fall asleep 90 times a day, and they sleep for about six minutes at a time.', '반면 여왕개미는 하루에 90번 잠을 자는데, 한 번에 약 6분 정도 잠을 잔다.', '비교급', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'This means that they sleep for about nine hours each day.', '이는 그들이 매일 약 9시간 동안 잠을 잔다는 것을 의미합니다.', '접속사/관계대명사 that', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'In short, ants sleep and rest just like us, though they do so in a diﬀ  erent way.', '간단히 말해서, 개미는 우리와 마찬가지로 잠을 자고 휴식을 취하지만, 그 방식은 다릅니다.', '양보의 접속사 / 최상급', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '7  How do worker ants rest?', '7 일개미는 어떻게 쉬나요?', '의문사 구문 / 비교급', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '8   Worker ants sleep for about hours a day while queen ants sleep for about hours a day.', '8 일개미는 하루에 약 몇 시간 동안 잠을 자고, 여왕개미는 하루에 약 시간 동안 잠을 잔다.', '시간의 접속사 / 비교급', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'GRAMMAR & WRITING Choose and write.', '문법 및 쓰기 선택하고 쓰기.', '현재분사/동명사', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '9  Look at the boy (dancing / danced) on the stage.', '9 무대 위에서 춤추는 소년을 보세요.', '현재분사/동명사', 46);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '10  (Since / Th  ough) he has two left   feet, he enjoys dancing.', '10 (그 이후로 / 그래도) 그는 왼쪽 발이 두 개 있어서 춤추는 것을 즐긴다.', '이유의 접속사 / 현재분사/동명사', 43);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Can you tell me about the machine?', '기계에 대해 말해줄 수 있나요?', '조동사', 34);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Jenkins stood before his class.', 'Jenkins는 수업 앞에 섰습니다.', '시간의 접속사', 47);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'He had a large jar and a big bag on the teacher’s desk.', '그는 선생님 책상 위에 큰 항아리와 큰 가방을 가지고 있었습니다.', '비교급', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'When the class began, he picked up the jar and started to fi  ll it with golf balls  from the bag.', '수업이 시작되자 그는 항아리를 집어들고 가방에 들어 있던 골프공을 채우기 시작했습니다.', '시간의 접속사 / to부정사', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'He asked the students, “Is the jar full?” They all said, “Yes.', '그는 학생들에게 “항아리가 가득 찼습니까?”라고 물었습니다. 그들은 모두 “그렇습니다.', '일반 문장', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '” The teacher took a box of small stones  out of the bag and poured them into the jar.', '” 선생님은 가방에서 작은 돌 한 상자를 꺼내서 항아리에 부었습니다.', '비교급', 47);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'He shook the jar a little, and the stones rolled into the open areas between the golf balls.', '그는 단지를 조금 흔들었고, 돌들은 골프공 사이의 열린 공간으로 굴러갔습니다.', '일반 문장', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'He asked the same question and got the same answer from his students.', '그는 같은 질문을 했고 학생들에게서도 같은 대답을 얻었다.', '비교급', 47);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Next, the teacher took out a bottle of sand and poured it into the jar.', '다음으로 선생님은 모래 한 병을 꺼내서 그 안에 부어 주셨습니다.', '비교급', 47);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'After he watched the sand fill the spaces between the stones, he asked once more, “Is the jar full?” All the students replied, “Yes.', '그는 돌 사이에 모래가 채워지는 것을 보고 다시 한 번 “항아리가 가득 찼습니까?”라고 물었습니다. 학생들은 모두 “그렇습니다.', '시간의 접속사 / 비교급', 47);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Jenkins took a can of apple juice  out of the bag.', 'Jenkins는 가방에서 사과 주스 캔을 꺼냈습니다.', '조동사', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'He poured the apple juice into the jar, and his students watched it fill the spaces in the sand.', '그는 사과 주스를 병에 부었고 그의 학생들은 그것이 모래의 공간을 채우는 것을 지켜보았습니다.', '일반 문장', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '“Now, ” the teacher said, “I want you to understand that your life is just like the jar.', '“이제” 선생님이 말씀하셨습니다. “네 인생은 단지 항아리와 같다는 것을 이해해 주기를 바랍니다.', 'to부정사 / 접속사/관계대명사 that', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'The golf balls are what is most important in life: your family, your friends, your health, and your dreams.', '골프공은 인생에서 가장 중요한 것입니다. 가족, 친구, 건강, 그리고 꿈입니다.', '의문사 구문 / 최상급', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Even when everything else is lost, your life can still be full.', '다른 모든 것을 잃어도 당신의 삶은 여전히 ​​충만할 수 있습니다.', '시간의 접속사 / 조동사', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'The stones are the other things valued by people, like your job, your house, and your car.', '돌은 직업, 집, 자동차와 같이 사람들이 소중히 여기는 다른 것입니다.', '비교급', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'The sand is all the small things.', '모래는 모두 작은 것입니다.', '일반 문장', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '” “If you put the sand into the jar first, ” he said, “there’s no room for the stones or the golf balls.', '“병에 모래를 먼저 넣으면 돌이나 골프공이 들어갈 자리가 없어요.', '조건의 접속사', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'The same goes for life.', '인생도 마찬가지다.', '일반 문장', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'If you spend all your time and energy on the small things, you will never have room for what is really important to you.', '작은 일에 모든 시간과 에너지를 쏟는다면 자신에게 정말 중요한 것을 담을 공간이 전혀 없을 것입니다.', '조건의 접속사 / to부정사', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Take care of the balls first - the things that really matter.', '공을 먼저 관리하세요. 정말 중요한 것입니다.', '접속사/관계대명사 that / 비교급', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '” One student sitting in the back raised her hand and asked, “What does the apple juice mean?” Mr.', '뒤쪽에 앉은 한 학생이 손을 들더니 “사과즙이 무슨 뜻이에요?”라고 물었다. 씨.', '의문사 구문 / 현재분사/동명사', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Jenkins smiled, “I’m glad you asked.', '젠킨스는 미소를 지었다. “물어주셔서 기쁘네요.', '일반 문장', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'It just shows that though your life may seem full, there’s always room for a cool drink with a friend.', '이는 인생이 꽉 차 있는 것처럼 보일지라도 친구와 함께 시원한 음료를 마실 수 있는 여지가 항상 있다는 것을 보여줍니다.', '양보의 접속사 / 접속사/관계대명사 that', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '” What are your golf balls, small stones, and sand?', '”당신의 골프공, 작은 돌, 모래는 무엇인가요?', '의문사 구문', 48);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'When I feel down, you make my life brighter.', '기분이 우울할 때 당신은 내 삶을 더 밝게 만들어줍니다.', '시간의 접속사 / 비교급', 49);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'When I am happy, you make me dance and sing.', '내가 기쁠 때 당신은 나를 춤추고 노래하게 만드세요.', '시간의 접속사 / 현재분사/동명사', 49);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I will carry you around at all times.', '나는 항상 당신을 데리고 다닐 것입니다.', '조동사', 49);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Dami When I am happy, you make When I am happy, you make Dear Busy Bees, Thank you, Bees.', '다미 내가 기쁠 때 네가 만든다. 내가 기쁠 때 네가 만드는 Dear Busy Bees, Thank you Bees.', '시간의 접속사 / 사역동사', 49);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'How can I enjo y my tea without the hone y you make?', '당신이 만드는 꿀 없이 어떻게 차를 즐길 수 있나요?', '의문사 구문 / 조동사', 49);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'My t ea t ast es so sweet.', '내 차 맛이 너무 달콤해요.', '일반 문장', 0);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'I am going to plant many flowers for you.', '나는 당신을 위해 많은 꽃을 심을 것입니다.', 'to부정사 / 현재분사/동명사', 49);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'B I’m sorry, but we don’t have one near here.', 'B 죄송합니다만, 이 근처에는 그런 곳이 없어요.', '사역동사', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'A Do you want me to play baduk with you?', 'A 나랑 바둑 좀 칠까?', 'to부정사', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '↟ Friday evening is the time when my family likes to go for a walk.', '↟ 금요일 저녁은 우리 가족이 산책하기를 좋아하는 시간입니다.', '시간의 접속사 / to부정사', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '↟I wonder if they are angry.', '↟화났는지 궁금해요.', '조건의 접속사 / 비교급', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'Lesson 4 Be Positive, Be Happy A I’d like to talk about Frida Kahlo.', 'Lesson 4 긍정적으로, 행복하게 A 저는 프리다 칼로(Frida Kahlo)에 대해 이야기하고 싶습니다.', 'to부정사', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'A I want to spend more time on social media.', 'A 소셜 미디어에 더 많은 시간을 보내고 싶습니다.', 'to부정사 / 비교급', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'B What makes you say that?', 'B 왜 그렇게 말해요?', '접속사/관계대명사 that / 의문사 구문', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', 'A I can make more friends from around the world.', 'A 나는 전 세계에서 더 많은 친구를 사귈 수 있습니다.', '조동사 / 비교급', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '↟Jake has been sleeping all afternoon.', '↟Jake는 오후 내내 자고 있었습니다.', '완료시제 / 현재분사/동명사', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (12, 'Extra/Reading_for_Fun', '↟It was so cold that I put on my coat.', '↟너무 추워서 코트를 입었어요.', '접속사/관계대명사 that', 50);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (13, 'Listening', 'I’ve been waiting for you since 2 o’clock.', '나는 2시부터 너를 쭉 기다리고 있어.', '현재완료 진행형', 52);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (13, 'Main', 'I have been wondering about this for a long time.', '나는 오랫동안 이것에 대해 궁금해하고 있어.', '현재완료 진행형', 60);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (13, 'Main', 'She was so busy that she forgot the meeting.', '그녀는 너무 바빠서 회의를 잊어버렸다.', 'so ~ that 구문', 64);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (13, 'Reading', 'I have been collecting old stamps for three years.', '나는 3년 동안 오래된 우표를 수집해 오고 있다.', '현재완료 진행형', 75);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (13, 'Reading', 'The cake was so delicious that we ate it all.', '그 케이크는 너무 맛있어서 우리는 그것을 다 먹었다.', 'so ~ that 구문', 78);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (14, 'Listening', 'I don’t know if it will rain tomorrow.', '내일 비가 올지 안 올지 모르겠어.', '접속사 if/whether (명사절)', 72);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (14, 'Main', 'This is the place where I first met my best friend.', '이곳은 내가 나의 가장 친한 친구를 처음 만난 곳이야.', '관계부사(where)', 74);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (14, 'Main', 'Tell me the reason why you are late.', '네가 늦은 이유를 나에게 말해줘.', '관계부사(why)', 80);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (14, 'Reading', 'I’m curious whether she will come to the party.', '그녀가 파티에 올지 궁금해.', '접속사 if/whether (명사절)', 95);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (14, 'Reading', 'This is the way they solve the problem.', '이것이 그들이 문제를 해결하는 방식이다.', '관계부사(how)', 98);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (15, 'Listening', 'When I arrived, the performance had already started.', '내가 도착했을 때 공연은 이미 시작되어 있었다.', '과거완료', 92);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (15, 'Main', 'He was a soccer player, but it was literature that he loved most.', '그는 축구 선수였지만 가장 사랑한 것은 문학이었다.', 'It ~ that 강조구문', 112);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (15, 'Main', 'Jake was late because he had missed the bus.', '제이크는 버스를 놓쳤었기 때문에 늦었다.', '과거완료', 115);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (16, 'Listening', 'It is important for us to protect nature.', '우리가 자연을 보호하는 것은 중요하다.', 'to부정사 의미상 주어', 112);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (16, 'Main', 'It is important for everyone to value the resources.', '모두가 자원을 소중히 여기는 것이 중요하다.', 'to부정사 의미상 주어', 125);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (16, 'Main', 'If she had a car', ' she would drive everywhere.', 'G0604', 상);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (17, 'Listening', 'I study English', ' listening to music.', 'G0701',  V-ing);
