INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (18, 'Listening', 'She must have been hungry.', '그녀는 배가 고팠음이 틀림없다.', '과거 추측(must have pp)', 152);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (18, 'Listening', 'I should have studied harder.', '나는 공부를 더 열심히 했어야 했다.', '과거 후회(should have pp)', 154);
INSERT INTO sentences (unit_id, section, en_text, ko_text, grammar_tag, page_num) VALUES (18, 'Main', 'I’ll visit you during vacation, which begins tomorrow.', '나는 내일 시작되는 방학 동안 너를 방문할 것이다.', '계속적 용법의 관계대명사', 상);
